SELECT neighbour_id, average_price
FROM neighborhood_stats
ORDER BY average_price DESC;

SELECT total_properties
FROM neighborhood_stats
WHERE neighbour_id = 1;

SELECT neighbour_id, average_rating
FROM neighborhood_stats
WHERE average_rating = (SELECT MAX(average_rating) FROM neighborhood_stats);

SELECT average_price
FROM neighborhood_stats
WHERE neighbour_id = (SELECT neighbour_id FROM neighborhoods WHERE neighbour_name = 'Haringey');
